import { useState } from 'react';import { useQuery } from '@tanstack/react-query';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { usePermissions } from '@/hooks/usePermissions';import { apiErrorMessage } from '@/lib/apiClient';import { vendorApi } from '../api/vendorApi';import { useSaveQuotation,useSuppliers,useVendorQuotations } from '../api/useVendors';import { PriceComparisonTable } from '../components/PriceComparisonTable';import { QuotationForm } from '../components/QuotationForm';import { QuotationTable } from '../components/QuotationTable';import { VendorModal } from '../components/VendorModal';import type { QuotationFormValues,SupplierQuotation } from '../types';
export const QuotationsPage=()=>{const [filters,setFilters]=useState({search:'',status:'',rfq_reference:''});const [comparisonRfq,setComparisonRfq]=useState('');const [vendorId,setVendorId]=useState(0);const [editing,setEditing]=useState<SupplierQuotation|null|undefined>();const {can}=usePermissions();const list=useVendorQuotations({...filters,per_page:100});const suppliers=useSuppliers({status:'active',per_page:100});const target=editing?.vendor_id??vendorId;const save=useSaveQuotation(target,editing?.id);const comparison=useQuery({queryKey:['vendors','quotation-comparison',comparisonRfq],queryFn:()=>vendorApi.compare(comparisonRfq),enabled:comparisonRfq.length>0});const submit=async(v:QuotationFormValues)=>{await save.mutateAsync(v);setEditing(undefined);};const openEdit=async(q:SupplierQuotation)=>{try{setVendorId(q.vendor_id);setEditing(await vendorApi.quotation(q.vendor_id,q.id));}catch{setEditing(q);}};return <div className="space-y-6 text-slate-800 dark:text-slate-100"><header><p className="text-xs font-bold uppercase tracking-[.18em] text-indigo-600">Vendor Management</p><h1 className="mt-2 text-2xl font-bold">Supplier Quotations</h1><p className="mt-1 text-sm text-slate-500">RFQ references, quotation history, line pricing, and supplier comparison.</p></header><section className="rounded-xl border bg-white p-5 dark:border-slate-700 dark:bg-slate-900"><h2 className="font-bold">Price Comparison</h2><div className="mt-3 flex gap-2"><input placeholder="Enter RFQ reference" value={comparisonRfq} onChange={e=>setComparisonRfq(e.target.value)} className="h-10 min-w-64 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><span className="self-center text-xs text-slate-500">Comparisons remain separated by currency.</span></div><div className="mt-4"><PriceComparisonTable rows={comparison.data??[]} isLoading={comparison.isLoading}/></div></section><section><div className="flex flex-wrap gap-3 rounded-t-xl border border-b-0 bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><input placeholder="Search quotation…" value={filters.search} onChange={e=>setFilters({...filters,search:e.target.value})} className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><input placeholder="RFQ reference" value={filters.rfq_reference} onChange={e=>setFilters({...filters,rfq_reference:e.target.value})} className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><select value={filters.status} onChange={e=>setFilters({...filters,status:e.target.value})} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value="">All statuses</option>{['draft','received','under_review','accepted','rejected','expired'].map(x=><option key={x} value={x}>{x.replaceAll('_',' ')}</option>)}</select>{can('vendors.create')?<div className="ml-auto flex gap-2"><select value={vendorId} onChange={e=>setVendorId(Number(e.target.value))} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value={0}>Select supplier</option>{suppliers.data?.data.map(x=><option key={x.attributes.id} value={x.attributes.id}>{x.attributes.company_name}</option>)}</select><Button disabled={!vendorId} onClick={()=>setEditing(null)}>Add Quotation</Button></div>:null}</div>{list.error||comparison.error?<Alert variant="danger" title="Quotation data unavailable">{apiErrorMessage(list.error||comparison.error)}</Alert>:null}<div className="overflow-hidden rounded-b-xl border bg-white dark:border-slate-700 dark:bg-slate-900"><QuotationTable quotations={list.data?.data.map(x=>x.attributes)??[]} isLoading={list.isLoading} onEdit={can('vendors.update')?q=>void openEdit(q):undefined}/></div></section>{editing!==undefined&&target>0?<VendorModal title={editing?'Edit Quotation':'Add Quotation'} onClose={()=>setEditing(undefined)} wide><QuotationForm quotation={editing} currency={suppliers.data?.data.find(x=>x.attributes.id===target)?.attributes.currency} onSubmit={v=>void submit(v)} onCancel={()=>setEditing(undefined)} isLoading={save.isPending}/>{save.error?<Alert variant="danger" title="Unable to save quotation">{apiErrorMessage(save.error)}</Alert>:null}</VendorModal>:null}</div>;};
